            pokemons.Add(new Pokemon("Paras", 0.3, 5.4, "Mushroom", "Effect Spore", "Bug & Grass", 1, "Parasect", "Burrows under the ground to gnaw on tree roots. The mushrooms on its back are called tochukaso.", 46, "The mushrooms on its back are called tochukaso. They grow by drawing nutrients from the host. They are highly valued as medicine for long life."));
            pokemons.Add(new Pokemon("Parasect", 1.0, 29.5, "Mushroom", "Effect Spore", "Bug & Grass", 1, "None", "The bug host is controlled by the mushrooms that have taken over its body. They scatter toxic spores.", 47, "The larger the mushroom on its back grows, the stronger the mushroom spores it scatters. It is said that the host insect is entirely controlled by the mushroom."));
            pokemons.Add(new Pokemon("Venonat", 1.0, 30.0, "Insect", "Compound Eyes", "Bug & Poison", 1, "Venomoth", "Its large eyes act as radar. In bright light, you can see that they are clusters of many tiny eyes.", 48, "Its small eyes are actually a collection of many tiny eyes. Using them, it can see in all directions. Its favorite food is small insects."));
