            pokemons.Add(new Pokemon("Dugtrio", 0.7, 33.3, "Mole", "Sand Veil", "Ground", 1, "None", "A team of Diglett triplets. It triggers huge earthquakes by burrowing underground.", 51, "These three Diglett are actually triplets. They work together to dig an impassable tunnel, and they can dig up to 60 miles deep."));
