            pokemons.Add(new Pokemon("Alakazam", 1.5, 48.0, "Psi", "Synchronize", "Psychic", 1, "None", "It has an incredibly high IQ of 5,000. Its brain can outperform a supercomputer.", 65, "Alakazam's brain is constantly growing. Its IQ is said to be around 5,000, and it remembers everything. It can use its psychic powers to levitate."));
            pokemons.Add(new Pokemon("Machop", 0.8, 19.5, "Superpower", "Guts", "Fighting", 1, "Machoke", "It lifts heavy Graveler repeatedly to strengthen its entire body. It uses every type of martial arts.", 66, "Its muscles are made of special fibers that allow it to punch and throw with incredible power. It trains constantly, even in its sleep."));
            pokemons.Add(new Pokemon("Machoke", 1.5, 70.5, "Superpower", "Guts", "Fighting", 1, "Machamp", "Its muscular body is so powerful that the belt it wears is needed to control its strength.", 67, "Machoke has immense strength. It is known to be able to lift heavy objects with ease. The belt it wears is essential to keep its power under control."));
            pokemons.Add(new Pokemon("Machamp", 1.6, 130.0, "Superpower", "Guts", "Fighting", 1, "None", "It has four powerful arms. It can strike from any angle and can throw a hundred punches in two seconds.", 68, "Machamp is so strong that it can move mountains. Its four arms allow it to punch and grapple from any position. It can deliver a flurry of punches faster than the eye can follow."));
            pokemons.Add(new Pokemon("Bellsprout", 0.7, 4.0, "Flower", "Chlorophyll", "Grass & Poison", 1, "Weepinbell", "It prefers hot and humid places. It is quick at capturing prey with its vines.", 69, "Bellsprout's thin body is flexible and allows it to bend and sway to avoid attacks. It uses its roots to absorb moisture and its vines to attack."));
            pokemons.Add(new Pokemon("Weepinbell", 1.0, 6.4, "Flycatcher", "Chlorophyll", "Grass & Poison", 1, "Victreebel", "When hungry, it swings its leafy parts to create a hypnotic sway to lure in prey.", 70, "It spits out a sticky fluid to trap prey. The fluid dissolves the prey slowly while the Pokémon waits."));
            pokemons.Add(new Pokemon("Victreebel", 1.7, 15.5, "Flycatcher", "Chlorophyll", "Grass & Poison", 1, "None", "It lures prey into its mouth with a honeylike aroma. The prey is dissolved in a fluid with a major acidic punch.", 71, "Victreebel has a large vine on its back. It uses this vine to move and to attack. It lives in colonies deep in jungles, where it waits for unsuspecting prey."));
            pokemons.Add(new Pokemon("Tentacool", 0.9, 45.5, "Jellyfish", "Clear Body", "Water & Poison", 1, "Tentacruel", "It drifts through the sea searching for prey. Its poisonous tentacles break off sometimes but grow back.", 72, "Tentacool floats on the surface of the sea. Its eyes are almost invisible. Its body is composed of 99% water, so it is transparent."));
            pokemons.Add(new Pokemon("Tentacruel", 1.6, 55.0, "Jellyfish", "Clear Body", "Water & Poison", 1, "None", "It has 80 tentacles. They stretch and shrink freely and can entangle or poison its prey.", 73, "When its 80 tentacles absorb water, they stretch and can entangle boats and cause them to sink. It is known to be a very dangerous sea creature."));
            pokemons.Add(new Pokemon("Geodude", 0.4, 20.0, "Rock", "Rock Head", "Rock & Ground", 1, "Graveler", "It uses its arms to steadily climb steep mountain paths. It is known to roll down mountains without injury.", 74, "Geodude is commonly found near mountain trails. It looks like a rock, so many people step on it by accident. When stepped on, it gets angry and attacks."));
            pokemons.Add(new Pokemon("Graveler", 1.0, 105.0, "Rock", "Rock Head", "Rock & Ground", 1, "Golem", "It rolls down slopes to move. It rolls over any obstacle without slowing or caring about damage.", 75, "Graveler grows by eating rocks. It prefers to eat rocks that have been covered in moss. It rolls down mountains so often that its body is pockmarked and dented."));
            pokemons.Add(new Pokemon("Golem", 1.4, 300.0, "Megaton", "Rock Head", "Rock & Ground", 1, "None", "It sheds its skin once a year. The discarded shell hardens and returns to the soil to enrich it.", 76, "Golem's body is so hard that dynamite can't scratch it. It sheds its skin once a year, and the old skin is prized for its hardness."));
            pokemons.Add(new Pokemon("Ponyta", 1.0, 30.0, "Fire Horse", "Run Away", "Fire", 1, "Rapidash", "It is a weak runner immediately after birth. Gradually, it competes with its friends to become faster.", 77, "Ponyta's legs are incredibly strong. At birth, it is weak, but it trains constantly with its herd to develop its speed and strength."));
            pokemons.Add(new Pokemon("Rapidash", 1.7, 95.0, "Fire Horse", "Run Away", "Fire", 1, "None", "It canters around to show off its breathtaking speed and fiery mane. It is a sight to behold.", 78, "Rapidash is incredibly fast. It can gallop at over 150 miles per hour. Its mane is made of fire, and it can jump over the Eiffel Tower in one leap."));
            pokemons.Add(new Pokemon("Slowpoke", 1.2, 36.0, "Dopey", "Oblivious", "Water & Psychic", 1, "Slowbro", "It is incredibly slow and dopey. It takes five seconds to feel pain when it is hit.", 79, "Slowpoke uses its tail to fish for prey. It is so slow that it doesn't even notice when its tail is bitten. It takes a long time to react to anything."));
            pokemons.Add(new Pokemon("Slowbro", 1.6, 78.5, "Hermit Crab", "Oblivious", "Water & Psychic", 1, "None", "A Shellder bit its tail, and they have become partners. They help each other and enjoy life together.", 80, "Slowbro lives with a Shellder attached to its tail. The Shellder bites down hard, giving Slowbro a rush of power. If the Shellder lets go, Slowbro becomes Slowpoke again."));
            pokemons.Add(new Pokemon("Magnemite", 0.3, 6.0, "Magnet", "Magnet Pull", "Electric & Steel", 1, "Magneton", "It levitates using magnetic waves. The units at its sides are its powerful electromagnets.", 81, "Magnemite floats through the air using electromagnetism. It generates a magnetic field that can attract metal objects from a distance."));
            pokemons.Add(new Pokemon("Magneton", 1.0, 60.0, "Magnet", "Magnet Pull", "Electric & Steel", 1, "None", "It is actually three Magnemite linked by magnetism. It generates powerful radio waves.", 82, "Magneton is a union of three Magnemite. It generates a strong magnetic field that can disrupt electronic devices. It is often seen in power plants."));
            pokemons.Add(new Pokemon("Farfetch'd", 0.8, 15.0, "Wild Duck", "Keen Eye", "Normal & Flying", 1, "None", "It can't live without the leek it holds. That's why it protects the leek from attackers with its life.", 83, "Farfetch'd always carries a leek stalk. It uses this stalk as a weapon. The leek is also its favorite food, and it will defend it fiercely."));
            pokemons.Add(new Pokemon("Doduo", 1.4, 39.2, "Twin Bird", "Run Away", "Normal & Flying", 1, "Dodrio", "Its short wings make flying difficult. Instead, it has become a fast runner that can keep up with cars.", 84, "Doduo's two heads communicate telepathically. They sleep in shifts, so one head is always awake and watching for danger."));
            pokemons.Add(new Pokemon("Dodrio", 1.8, 85.2, "Triple Bird", "Run Away", "Normal & Flying", 1, "None", "It has three heads that happily sleep in turns. It is an extremely rare sight to see all three awake.", 85, "When Doduo evolves into Dodrio, one of its heads splits into two. The three heads now represent joy, sorrow, and anger. They rarely agree on anything."));
            pokemons.Add(new Pokemon("Seel", 1.1, 90.0, "Sea Lion", "Thick Fat", "Water", 1, "Dewgong", "It loves freezing-cold conditions. It enjoys swimming in frigid climates with temperatures around 14 degrees Fahrenheit.", 86, "Seel is covered in a layer of blubber that protects it from the cold. It lives in icy waters and loves to swim in the frigid temperatures."));
            pokemons.Add(new Pokemon("Dewgong", 1.7, 120.0, "Sea Lion", "Thick Fat", "Water & Ice", 1, "None", "It stores thermal energy in its body. It swims at a steady 8 knots, even in intensely cold waters.", 87, "Dewgong loves to snooze on ice floes. Its body is covered in a pure white fur that provides excellent camouflage in the snow and ice."));
            pokemons.Add(new Pokemon("Grimer", 0.9, 30.0, "Sludge", "Stench", "Poison", 1, "Muk", "It was born from polluted sludge in the sea. It loves filthy things and enjoys drinking dirty water.", 88, "Grimer's body is made of sludge. It oozes through dirty streets and sewers. It loves filthy places and will eat anything that is dirty."));
            pokemons.Add(new Pokemon("Muk", 1.2, 30.0, "Sludge", "Stench", "Poison", 1, "None", "It is usually underground. It emerges from filthy places and moves through them, spreading germs everywhere.", 89, "Muk is so poisonous that even touching it can cause poisoning. Its body gives off a foul odor that can cause fainting from a mile away."));
            pokemons.Add(new Pokemon("Shellder", 0.3, 4.0, "Bivalve", "Shell Armor", "Water", 1, "Cloyster", "It is encased in a shell that is harder than diamond. Inside, however, it is surprisingly tender.", 90, "Shellder's shell is very hard. It can withstand any attack. It swims backwards by opening and closing its shell, and it uses its tongue to dig into sand."));
            pokemons.Add(new Pokemon("Cloyster", 1.5, 132.5, "Bivalve", "Shell Armor", "Water & Ice", 1, "None", "Its shell is extremely hard. It cannot be broken, even with a bomb. The shell opens only when it attacks.", 91, "Cloyster's shell is so hard it can withstand bombs. It fires spikes from its shell in all directions to fend off attackers. The spikes are made of the same material as its shell."));
            pokemons.Add(new Pokemon("Gastly", 1.3, 0.1, "Gas", "Levitate", "Ghost & Poison", 1, "Haunter", "It wraps its opponent in its gaseous body, stealing their life force. It is invisible to the naked eye.", 92, "Gastly is made of gas. It can slip through the smallest cracks. It hides in dark places and enjoys scaring people by whispering in their ears."));
            pokemons.Add(new Pokemon("Haunter", 1.6, 0.1, "Gas", "Levitate", "Ghost & Poison", 1, "Gengar", "It likes to lurk in the dark and lick hands with its gas-like tongue. It causes tremors that can't be explained.", 93, "Haunter is a dangerous Pokémon that licks its victims with its tongue, sapping their life away. It loves to play pranks on people and other Pokémon."));
            pokemons.Add(new Pokemon("Gengar", 1.5, 40.5, "Shadow", "Cursed Body", "Ghost & Poison", 1, "None", "It hides in shadows. It is said that if you feel a sudden chill, it means a Gengar is nearby.", 94, "Gengar likes to play pranks on people. It hides in the shadows of dark places. It can create a perfect, but sinister, illusion of itself."));
            pokemons.Add(new Pokemon("Onix", 8.8, 210.0, "Rock Snake", "Rock Head", "Rock & Ground", 1, "Steelix", "It twists and squirms through the ground. The thunderous roar of its tunneling echoes underground.", 95, "Onix tunnels through the ground at 50 miles per hour. It is known to cause earthquakes as it moves. Its body becomes smoother over time as it rubs against the ground."));
            pokemons.Add(new Pokemon("Drowzee", 1.0, 32.4, "Hypnosis", "Insomnia", "Psychic", 1, "Hypno", "It puts enemies to sleep and then eats their dreams. It can remember only the good dreams it has eaten.", 96, "Drowzee puts people to sleep and eats their dreams. It gets sick from eating nightmares. It has a special nose that helps it locate sleeping people."));
            pokemons.Add(new Pokemon("Hypno", 1.6, 75.6, "Hypnosis", "Insomnia", "Psychic", 1, "None", "It carries a pendulum-like device. There are some Hypno that assist in medical institutions for children who can't sleep.", 97, "Hypno carries a pendulum. It uses the pendulum to put opponents to sleep. It is said to eat the dreams of children, but only the pleasant ones."));
            pokemons.Add(new Pokemon("Krabby", 0.4, 6.5, "River Crab", "Hyper Cutter", "Water", 1, "Kingler", "It can be found near the sea. The large pincer has enormous power and can crush anything.", 98, "Krabby lives on beaches. It digs holes in the sand to build its nest. Its pincers are very strong, but they break off easily and grow back."));
            pokemons.Add(new Pokemon("Kingler", 1.3, 60.0, "Pincer", "Hyper Cutter", "Water", 1, "None", "Its large and hard pincer has 10,000 horsepower. However, it is so heavy that it is difficult to aim.", 99, "Kingler's pincer is incredibly powerful. It can crush anything, but it is so heavy that Kingler has trouble aiming it. It waves its huge pincer in the air to communicate."));
            pokemons.Add(new Pokemon("Voltorb", 0.5, 10.4, "Ball", "Soundproof", "Electric", 1, "Electrode", "It is said to camouflage itself as a Poké Ball. It will self-destruct with very little stimulus.", 100, "Voltorb was discovered when Poké Balls were invented. It looks just like a Poké Ball and will explode if startled. It is often found in power plants."));
            pokemons.Add(new Pokemon("Electrode", 1.2, 66.6, "Ball", "Soundproof", "Electric", 1, "None", "It stores an enormous amount of electric energy. It goes off with a thunderous explosion if you shake it.", 101, "Electrode stores vast amounts of electricity. The slightest shock can cause it to explode. It is known as the Bomb Ball Pokémon because of its tendency to explode."));
            pokemons.Add(new Pokemon("Exeggcute", 0.4, 2.5, "Egg", "Chlorophyll", "Grass & Psychic", 1, "Exeggutor", "Its six eggs use telepathy to communicate among themselves. It is believed to carry plant genes.", 102, "Exeggcute is made of six eggs that communicate telepathically. If even one egg is separated, they can quickly reunite. The shells are very tough."));
            pokemons.Add(new Pokemon("Exeggutor", 2.0, 120.0, "Coconut", "Chlorophyll", "Grass & Psychic", 1, "None", "It has three heads that think the same thoughts. When one head yawns, the other two also yawn.", 103, "Exeggutor's three heads all think the same thoughts. They are very social and love to interact. One of its heads will grow back if it falls off."));
            pokemons.Add(new Pokemon("Cubone", 0.4, 6.5, "Lonely", "Rock Head", "Ground", 1, "Marowak", "It wears the skull of its deceased mother. Its cries echo inside the skull, making for a melancholy sound.", 104, "Cubone wears the skull of its dead mother. It never removes the skull, as memories of its mother are tied to it. It cries at night, and the sound echoes eerily."));
            pokemons.Add(new Pokemon("Marowak", 1.0, 45.0, "Bone Keeper", "Rock Head", "Ground", 1, "None", "It is small and originally weak. Its temperament turned fierce when it began using bones as weapons.", 105, "Marowak has evolved from Cubone and is now tough and fierce. It uses a bone as a weapon, spinning it to create a protective barrier. It throws the bone like a boomerang."));
            pokemons.Add(new Pokemon("Hitmonlee", 1.5, 49.8, "Kicking", "Limber", "Fighting", 1, "None", "It is also called the Kicking Master. It can stretch and shrink its legs to strike an enemy far away.", 106, "Hitmonlee's legs are incredibly elastic. They can stretch to double their length. It uses its powerful legs to deliver devastating kicks to its opponents."));
            pokemons.Add(new Pokemon("Hitmonchan", 1.4, 50.2, "Punching", "Keen Eye", "Fighting", 1, "None", "Its punches are like rocket launches. It has a very short reach but can throw punches at the speed of a bullet.", 107, "Hitmonchan's punches are incredibly fast. It can throw punches so fast that they can't be seen. It uses a combination of jabs, hooks, and uppercuts."));
            pokemons.Add(new Pokemon("Lickitung", 1.2, 65.5, "Licking", "Own Tempo", "Normal", 1, "None", "Its tongue can stretch like a chameleon. It leaves a tingling sensation when it licks enemies.", 108, "Lickitung's tongue is twice as long as its body. It uses it to lick and clean itself, and to capture food. Its saliva is sticky and can paralyze opponents."));
            pokemons.Add(new Pokemon("Koffing", 0.6, 1.0, "Poison Gas", "Levitate", "Poison", 1, "Weezing", "Its body is filled with a poisonous gas. It floats into garbage dumps, seeking the fumes of rotting food.", 109, "Koffing's body is filled with a noxious gas. It floats through the air, looking for places with rotting garbage. The gas it emits smells terrible."));
            pokemons.Add(new Pokemon("Weezing", 1.2, 9.5, "Poison Gas", "Levitate", "Poison", 1, "None", "It loves the gases given off by rotting kitchen garbage. It can cause respiratory failure by spreading germs.", 110, "Weezing is formed when two Koffing fuse together. It has two bodies that are connected by a thin tube. It loves to inhale gases from rotting trash."));
            pokemons.Add(new Pokemon("Rhyhorn", 1.0, 115.0, "Spikes", "Lightning Rod", "Ground & Rock", 1, "Rhydon", "It is strong but not too bright. It can crash through even a skyscraper using its powerful charge.", 111, "Rhyhorn has a one-track mind. Once it starts charging, it doesn't stop until it falls asleep or crashes. Its short legs prevent it from turning well."));
            pokemons.Add(new Pokemon("Rhydon", 1.9, 120.0, "Drill", "Lightning Rod", "Ground & Rock", 1, "None", "It begins walking as soon as it is born. Its horn can rotate to drill through a boulder.", 112, "Rhydon's hide is so tough that it can withstand lava. Its horn can drill through solid rock. It has a short temper and will start charging at anything."));
            pokemons.Add(new Pokemon("Chansey", 1.1, 34.6, "Egg", "Natural Cure", "Normal", 1, "Blissey", "It is a rare Pokémon that lays delicious eggs. People are known to be kind to Chansey as a result.", 113, "Chansey is a kind and gentle Pokémon. It shares its highly nutritious eggs with injured people and Pokémon. It is very rare, and few have seen it."));
            pokemons.Add(new Pokemon("Tangela", 1.0, 35.0, "Vine", "Chlorophyll", "Grass", 1, "Tangrowth", "Its identity is obscured by blue vines. It is said to have vines that never stop growing.", 114, "Tangela's vines are covered in a fine blue fur. They are very strong and can entangle anything. The vines constantly grow and break off."));
            pokemons.Add(new Pokemon("Kangaskhan", 2.2, 80.0, "Parent", "Early Bird", "Normal", 1, "None", "It raises its offspring in its belly pouch. It is so fierce that it will punch a boulder to dust if it senses danger.", 115, "Kangaskhan is a caring parent. It carries its young in its pouch. If its child is threatened, it will become enraged and attack fiercely."));
            pokemons.Add(new Pokemon("Horsea", 0.4, 8.0, "Dragon", "Swift Swim", "Water", 1, "Seadra", "It makes its nest in the shade of coral reefs. If it senses danger, it sprays ink and flees.", 116, "Horsea lives in oceans and coral reefs. It sprays ink to escape when threatened. It is known for its excellent balance and swimming ability."));
            pokemons.Add(new Pokemon("Seadra", 1.2, 25.0, "Dragon", "Poison Point", "Water", 1, "Kingdra", "It is capable of swimming backward by rapidly fluttering its wing-like pectoral fins and stout tail.", 117, "Seadra is an excellent swimmer. It can swim in any direction, including backwards. Its fins are venomous and can cause paralysis."));
            pokemons.Add(new Pokemon("Goldeen", 0.6, 15.0, "Goldfish", "Swift Swim", "Water", 1, "Seaking", "Its dorsal and pectoral fins are beautifully developed. Females always release clouds of eggs when spawning.", 118, "Goldeen is a beautiful swimmer. It is known for its elegance in the water. Its fins are delicate and can be easily torn, so it is careful in battle."));
            pokemons.Add(new Pokemon("Seaking", 1.3, 39.0, "Goldfish", "Swift Swim", "Water", 1, "None", "In autumn, its body becomes more fatty in preparing to propose to a mate. It takes on beautiful colors.", 119, "Seaking's horn is incredibly powerful. It can bore through solid rock. During spawning season, they are beautiful and highly sought after by collectors."));
            pokemons.Add(new Pokemon("Staryu", 0.8, 34.5, "Star Shape", "Illuminate", "Water", 1, "Starmie", "It gathers in large numbers and creates a dazzling spectacle. If its center core glows, it is a sign of danger.", 120, "Staryu's center core is its heart. If it is damaged, the Staryu can regenerate it. Even if its limbs are cut off, it can regenerate them."));
            pokemons.Add(new Pokemon("Starmie", 1.1, 80.0, "Mysterious", "Illuminate", "Water & Psychic", 1, "None", "Its central core shines in seven colors. It is said to possess the ability to read the emotions of others.", 121, "Starmie's core glows with a beautiful, colorful light. It is rumored to be able to send signals into space. It is very intelligent and powerful."));
            pokemons.Add(new Pokemon("Mr. Mime", 1.3, 54.5, "Barrier", "Soundproof", "Psychic & Fairy", 1, "None", "It is a pantomime expert that can create invisible walls from nothing. It is an expert at reading emotions.", 122, "Mr. Mime is a master of pantomime. It can create invisible barriers that are very strong. It is known to be very protective of its young."));
            pokemons.Add(new Pokemon("Scyther", 1.5, 56.0, "Mantis", "Swarm", "Bug & Flying", 1, "Scizor", "It slashes through grass with its sharp scythes, moving too fast for the human eye to track.", 123, "Scyther is incredibly fast. It uses its scythes to cut through anything in its path. It is rarely seen because it moves so quickly."));
            pokemons.Add(new Pokemon("Jynx", 1.4, 40.6, "Human Shape", "Oblivious", "Ice & Psychic", 1, "None", "It speaks using a language that sounds like human speech. It is difficult to understand, but it is said that Jynx is communicating.", 124, "Jynx walks rhythmically as if it is dancing. Its movements are hypnotic and can put others in a trance. It is known for its strange language."));
            pokemons.Add(new Pokemon("Electabuzz", 1.1, 30.0, "Electric", "Static", "Electric", 1, "Electivire", "It loves to feed on strong electricity. It occasionally appears around power plants and other electrical installations.", 125, "Electabuzz is often found near power plants. It feeds on electricity and can cause blackouts. Its body crackles with electricity."));
            pokemons.Add(new Pokemon("Magmar", 1.3, 44.5, "Spitfire", "Flame Body", "Fire", 1, "Magmortar", "It dislikes cold places. It uses its volcanic heat to create flames and warm up its surroundings.", 126, "Magmar is born in volcanoes. Its body is so hot that it can melt anything. It breathes fire that can reach temperatures of over 2,000 degrees Fahrenheit."));
            pokemons.Add(new Pokemon("Pinsir", 1.5, 55.0, "Stag Beetle", "Hyper Cutter", "Bug", 1, "None", "It uses its powerful pincers to crush its prey. It is so strong that it can snap thick trees in half.", 127, "Pinsir's pincers are incredibly strong. They can crush anything. It uses them to grip and throw its opponents. It is known to be very territorial."));
            pokemons.Add(new Pokemon("Tauros", 1.4, 88.4, "Wild Bull", "Intimidate", "Normal", 1, "None", "They live in groups. The one with the longest and sharpest horns is the leader of the herd.", 128, "Tauros is very aggressive. It will attack anything that enters its territory. It whips itself with its tails to increase its speed and anger."));
            pokemons.Add(new Pokemon("Magikarp", 0.9, 10.0, "Fish", "Swift Swim", "Water", 1, "Gyarados", "It is a pathetic excuse for a Pokémon that is only capable of flopping and splashing. This behavior spurred research into its evolution.", 129, "Magikarp is considered the world's weakest Pokémon. It can only splash around. However, it is actually a very hardy Pokémon that can survive in any water."));
            pokemons.Add(new Pokemon("Gyarados", 6.5, 235.0, "Atrocious", "Intimidate", "Water & Flying", 1, "None", "Once it goes on a rampage, it doesn't stop until the entire area is destroyed. It is known as the god of destruction.", 130, "Gyarados's appearance is very fierce. It has an eternal rage that drives it to destroy everything. It is said that aGyarados appeared during a war to burn everything to the ground."));
            pokemons.Add(new Pokemon("Lapras", 2.5, 220.0, "Transport", "Water Absorb", "Water & Ice", 1, "None", "It has a gentle nature and enjoys carrying people on its back. Its high intelligence allows it to understand human speech.", 131, "Lapras is a gentle Pokémon that loves to ferry people across water. It can understand human speech and has a very high IQ. It is endangered due to overhunting."));
            pokemons.Add(new Pokemon("Ditto", 0.3, 4.0, "Transform", "Limber", "Normal", 1, "None", "It can reorganize its cells to transform into anything it sees. When it tries to remember something, it moves its body slightly.", 132, "Ditto's ability to transform is perfect. It can copy the appearance and abilities of any Pokémon. However, if it laughs, it will revert to its original form."));
            pokemons.Add(new Pokemon("Eevee", 0.3, 6.5, "Evolution", "Run Away", "Normal", 1, "Various", "Its genetic code is irregular. It may mutate if it is exposed to radiation from elemental stones.", 133, "Eevee is a rare Pokémon that can evolve into multiple forms. Its genetic makeup is unstable, allowing it to adapt to its environment. It is very popular as a pet."));
            pokemons.Add(new Pokemon("Vaporeon", 1.0, 29.0, "Bubble Jet", "Water Absorb", "Water", 1, "None", "Its cell structure is similar to water. It melts into water and becomes invisible when it wants to hide.", 134, "Vaporeon's composition is similar to water. It can blend into water and become invisible. It uses its fins to sense changes in the water."));
            pokemons.Add(new Pokemon("Jolteon", 0.8, 24.5, "Lightning", "Volt Absorb", "Electric", 1, "None", "It accumulates negative ions in its fur to create a powerful static charge. It can fire a lightning bolt from its fur.", 135, "Jolteon's fur is made of needles. It can shoot them at opponents. It becomes agitated when it is charged with electricity, and its fur stands on end."));
            pokemons.Add(new Pokemon("Flareon", 0.9, 25.0, "Flame", "Flash Fire", "Fire", 1, "None", "It has a flame sac inside its body. It inhales deeply, then blows out the flame at a temperature of 3,000 degrees Fahrenheit.", 136, "Flareon stores heat in its body. It can reach temperatures of over 1,600 degrees. It cools down by blowing out flames from its mouth."));
            pokemons.Add(new Pokemon("Porygon", 0.8, 36.5, "Virtual", "Trace", "Normal", 1, "Porygon2", "It is the first Pokémon created using modern science. It can travel through electronic space.", 137, "Porygon is an artificial Pokémon. It was created using the latest technology. It can travel through cyberspace and is used for data exploration."));
            pokemons.Add(new Pokemon("Omanyte", 0.4, 7.5, "Spiral", "Swift Swim", "Rock & Water", 1, "Omastar", "It was resurrected from a fossil using modern science. It swam through ancient seas by twisting its ten tentacles.", 138, "Omanyte lived in the sea long ago. It used its tentacles to catch prey. It was resurrected from a fossil and is now being studied."));
            pokemons.Add(new Pokemon("Omastar", 1.0, 35.0, "Spiral", "Swift Swim", "Rock & Water", 1, "None", "Its heavy shell is thought to be the reason it went extinct. It wrapped its prey with its tentacles to prevent escape.", 139, "Omastar's shell was too heavy, making it difficult to catch prey. It went extinct for this reason. Its bite is incredibly powerful."));
            pokemons.Add(new Pokemon("Kabuto", 0.5, 11.5, "Shellfish", "Swift Swim", "Rock & Water", 1, "Kabutops", "It is a Pokémon that was resurrected from a fossil. It uses its eyes to look around while it is still buried.", 140, "Kabuto lived in the sea long ago. It used its shell to protect itself. It was resurrected from a fossil and is very rare."));
            pokemons.Add(new Pokemon("Kabutops", 1.3, 40.5, "Shellfish", "Swift Swim", "Rock & Water", 1, "None", "It is thought to have gone extinct because its shell grew too large and heavy, making it unable to feed.", 141, "Kabutops was a fierce predator. It used its sharp scythes to catch prey. It could slice through its prey with ease."));
            pokemons.Add(new Pokemon("Aerodactyl", 1.8, 59.0, "Fossil", "Rock Head", "Rock & Flying", 1, "None", "It was resurrected from a fossil using science. It is aggressive and attacks with its serrated saw-like fangs.", 142, "Aerodactyl was a powerful predator in ancient times. It ruled the skies and attacked from above. It uses its sharp fangs to tear apart its prey."));
            pokemons.Add(new Pokemon("Snorlax", 2.1, 460.0, "Sleeping", "Immunity", "Normal", 1, "None", "It is not satisfied unless it eats over 900 pounds of food daily. When it is done eating, it immediately dozes off.", 143, "Snorlax is the heaviest Pokémon. It sleeps and eats constantly. It is so heavy that it can cause earthquakes when it walks."));
            pokemons.Add(new Pokemon("Articuno", 1.7, 55.4, "Freeze", "Pressure", "Ice & Flying", 1, "None", "It is a legendary bird Pokémon that can control ice. It creates blizzards to freeze its enemies.", 144, "Articuno is a legendary bird. It appears when it snows. Its wings are made of ice, and it can freeze water vapor in the air to make snow."));
            pokemons.Add(new Pokemon("Zapdos", 1.6, 52.6, "Electric", "Pressure", "Electric & Flying", 1, "None", "A legendary bird Pokémon that appears from thunderclouds. It can control electricity and cause thunderstorms.", 145, "Zapdos is a legendary bird. It lives in thunderclouds and controls lightning. It causes thunderstorms wherever it goes."));
            pokemons.Add(new Pokemon("Moltres", 2.0, 60.0, "Flame", "Pressure", "Fire & Flying", 1, "None", "It is one of the legendary bird Pokémon. Its appearance is said to indicate the coming of spring.", 146, "Moltres is a legendary bird. It can control fire and bring early spring. It is said that its wings are made of fire."));
            pokemons.Add(new Pokemon("Dratini", 1.8, 3.3, "Dragon", "Shed Skin", "Dragon", 1, "Dragonair", "It is called the Mirage Pokémon because so few have seen it. It sheds its skin and becomes larger.", 147, "Dratini is a rare Pokémon. It sheds its skin as it grows. It lives in clean lakes and rivers and is very shy."));
            pokemons.Add(new Pokemon("Dragonair", 4.0, 16.5, "Dragon", "Shed Skin", "Dragon", 1, "Dragonite", "Its crystalline orbs glow with power. It controls the weather and is said to live in the seas and lakes.", 148, "Dragonair has the power to change the weather. It flies by emitting a strange energy. It is very beautiful and mysterious."));
            pokemons.Add(new Pokemon("Dragonite", 2.2, 210.0, "Dragon", "Inner Focus", "Dragon & Flying", 1, "None", "It is known as the sea guardian. It flies over the oceans and rescues people from drowning.", 149, "Dragonite is a kind and gentle Pokémon. It will rescue anyone lost at sea. It can fly faster than the speed of sound."));
            pokemons.Add(new Pokemon("Mewtwo", 2.0, 122.0, "Genetic", "Pressure", "Psychic", 1, "None", "It was created by scientists after years of genetic engineering. It has the most savage heart of all Pokémon.", 150, "Mewtwo is a powerful Pokémon created from Mew's DNA. It is very aggressive and only cares about its own survival. It is considered one of the strongest Pokémon."));
            pokemons.Add(new Pokemon("Mew", 0.4, 4.0, "New Species", "Synchronize", "Psychic", 1, "None", "It is said to possess the genes of all Pokémon. It is so rare that it is said to be a mirage.", 151, "Mew is a very rare and mysterious Pokémon. It can make itself invisible and can learn any move. It is believed to be the ancestor of all Pokémon."));
            pokemons.Add(new Pokemon("Chikorita", 0.9, 6.4, "Leaf", "Overgrow", "Grass", 1, "Bayleef", "A sweet aroma gently emanates from the leaf on its head. It is docile and loves to bask in the sun.", 152, "Chikorita uses the leaf on its head to determine the temperature and humidity. It is a very affectionate Pokémon that loves to be pampered."));
            pokemons.Add(new Pokemon("Bayleef", 1.2, 15.8, "Leaf", "Overgrow", "Grass", 1, "Meganium", "The buds that ring its neck give off a spicy aroma that perks people up. It is said to be able to purify the air.", 153, "The scent from the leaves around its neck has a stimulating effect that revitalizes anyone who smells it. It loves to sunbathe."));
            pokemons.Add(new Pokemon("Meganium", 1.8, 100.5, "Herb", "Overgrow", "Grass", 1, "None", "Its breath has the fantastic ability to revive dead plants and flowers. It is known for its calming aroma.", 154, "The fragrance of Meganium's breath can bring dead plants back to life and soothe the feelings of those who inhale it. It is a very gentle Pokémon."));
            pokemons.Add(new Pokemon("Cyndaquil", 0.5, 7.9, "Fire Mouse", "Blaze", "Fire", 1, "Quilava", "It is timid, and always curls itself up in a ball. If attacked, it flares up its back for protection.", 155, "Cyndaquil is a timid Pokémon that always stays curled up. The flames on its back are a sign of its health and mood; they flare up when it is angry or surprised."));
            pokemons.Add(new Pokemon("Quilava", 0.9, 19.0, "Volcano", "Blaze", "Fire", 1, "Typhlosion", "It intimidates foes with intense gusts of flames and super-heated air. Its fur is non-flammable.", 156, "Quilava is a calm and collected Pokémon. It uses its fiery breath to intimidate opponents and can create intense heat waves. Its fur is fireproof."));
            pokemons.Add(new Pokemon("Typhlosion", 1.7, 79.5, "Volcano", "Blaze", "Fire", 1, "None", "If its rage peaks, it becomes so hot that anything that touches it will instantly go up in flames.", 157, "Typhlion can create explosive blasts of fire by rubbing its fur together. It is known to be a very powerful and intimidating Pokémon."));
            pokemons.Add(new Pokemon("Totodile", 0.6, 9.5, "Big Jaw", "Torrent", "Water", 1, "Croconaw", "It is small but rough and tough. It won't hesitate to bite at anything that moves, despite its size.", 158, "Totodile is a playful and energetic Pokémon, but its powerful jaws are not to be underestimated. It loves to chomp on anything it can get its mouth on."));
            pokemons.Add(new Pokemon("Croconaw", 1.1, 25.0, "Big Jaw", "Torrent", "Water", 1, "Feraligatr", "If it loses a fang, a new one grows back in its place. There are always 48 fangs lining its mouth.", 159, "Croconaw's jaws are incredibly strong, capable of crushing anything. It is a very aggressive hunter and is always looking for its next meal."));
            pokemons.Add(new Pokemon("Feraligatr", 2.3, 88.8, "Big Jaw", "Torrent", "Water", 1, "None", "It is hard to believe this fierce and violent Pokémon evolves from such a cute Totodile.", 160, "Feraligatr is a fearsome predator. It uses its immense jaws to grip its prey and then thrashes around wildly to tear it apart."));
            pokemons.Add(new Pokemon("Sentret", 0.8, 6.0, "Scout", "Run Away", "Normal", 1, "Furret", "It stands on its tail to see far away. It uses its forelegs to stand up and scout for danger.", 161, "Sentret is a very cautious Pokémon. It stands on its tail to get a better view of its surroundings and warn its colony of any approaching danger."));
            pokemons.Add(new Pokemon("Furret", 1.8, 32.5, "Long Body", "Run Away", "Normal", 1, "None", "It makes a nest to suit its long and skinny body. The nest is impossible for other Pokémon to enter.", 162, "Furret has a long, slender body that is perfect for squeezing into narrow spaces to hunt for prey. It is a very agile and quick Pokémon."));
            pokemons.Add(new Pokemon("Hoothoot", 0.7, 21.2, "Owl", "Insomnia", "Normal & Flying", 1, "Noctowl", "It always stands on one foot. It changes feet so fast, the movement can rarely be seen.", 163, "Hoothoot has an internal organ that senses the earth's rotation, allowing it to tell time precisely. It always stands on one leg to conserve energy."));
            pokemons.Add(new Pokemon("Noctowl", 1.6, 40.8, "Owl", "Insomnia", "Normal & Flying", 1, "None", "Its eyes are specially adapted. They concentrate even faint light and enable it to see in the dark.", 164, "Noctowl is a silent and deadly hunter. Its large eyes can see in almost total darkness, and it flies without making a sound to catch unsuspecting prey."));
            pokemons.Add(new Pokemon("Ledyba", 1.0, 10.8, "Five Star", "Swarm", "Bug & Flying", 1, "Ledian", "It is very timid. It always gathers in a group with others of its kind to protect itself.", 165, "Ledyba uses its legs to secrete a sticky fluid that allows it to cling to walls and ceilings. It is a very social Pokémon and is rarely seen alone."));
            pokemons.Add(new Pokemon("Ledian", 1.4, 35.6, "Five Star", "Swarm", "Bug & Flying", 1, "None", "It uses the stars on its back to communicate with others. It is said to be a messenger of the night sky.", 166, "Ledian's punches are powered by the light of the stars. The more stars there are in the night sky, the stronger its attacks become."));
            pokemons.Add(new Pokemon("Spinarak", 0.5, 8.5, "String Spit", "Swarm", "Bug & Poison", 1, "Ariados", "It spins a web that is thin but strong. It patiently waits for prey to get caught in it.", 167, "Spinarak's web is both strong and sticky. It uses the hook on its back to create a hole in its web where it hides, waiting for prey to become entangled."));
            pokemons.Add(new Pokemon("Ariados", 1.1, 33.5, "Long Leg", "Swarm", "Bug & Poison", 1, "None", "It attaches silk to its prey and sets it free. Later, it tracks the silk to find the prey's location.", 168, "Ariados is a very clever hunter. It releases its prey after attaching a silk thread, then follows the thread back to its target later. Its legs act as antennas."));
            pokemons.Add(new Pokemon("Crobat", 1.8, 75.0, "Bat", "Inner Focus", "Poison & Flying", 1, "None", "It has four wings, allowing it to fly faster and more quietly than Golbat. It is a very agile Pokémon.", 169, "Crobat has four wings that allow it to fly with incredible speed and maneuverability. It is so fast that it can fly so silently that its prey never sees it coming."));
            pokemons.Add(new Pokemon("Chinchou", 0.5, 12.0, "Angler", "Volt Absorb", "Water & Electric", 1, "Lanturn", "Its antennae, which evolved from fins, have positive and negative charges that attract prey.", 170, "Chinchou lives in the deep sea. The lights on its antennae are caused by a chemical reaction and are used to communicate and lure prey in the dark depths."));
            pokemons.Add(new Pokemon("Lanturn", 1.2, 22.5, "Light", "Volt Absorb", "Water & Electric", 1, "None", "The light it emits is so bright that it can illuminate the ocean's surface from a depth of over three miles.", 171, "Lanturn's light is strong enough to be seen from the surface of the water, even from the deepest parts of the ocean. It is often called the Deep - Sea Star."));
            pokemons.Add(new Pokemon("Pichu", 0.3, 2.0, "Tiny Mouse", "Static", "Electric", 1, "Pikachu", "It is not yet skilled at storing electricity. It may spark and shock itself when startled.", 172, "Pichu is a small, playful Pokémon. It is not very good at controlling its electricity, so it often shocks itself and its playmates, which makes it cry."));
            pokemons.Add(new Pokemon("Cleffa", 0.3, 3.0, "Star Shape", "Cute Charm", "Fairy", 1, "Clefairy", "If the impact site of a falling meteorite is found, this Pokémon is certain to be within its immediate area.", 173, "Cleffa are often seen on nights with shooting stars. They are said to have come from space on a meteor. Their body shape resembles a star."));
            pokemons.Add(new Pokemon("Igglybuff", 0.3, 1.0, "Balloon", "Cute Charm", "Normal & Fairy", 1, "Jigglypuff", "Its body is very elastic. By inhaling deeply, it can inflate itself to an enormous size.", 174, "Igglybuff's body is soft and bouncy. Its singing is not yet refined, but it practices constantly, hoping to one day have a beautiful voice like its evolution."));
            pokemons.Add(new Pokemon("Togepi", 0.3, 1.5, "Spike Ball", "Hustle", "Fairy", 1, "Togetic", "It is considered to be a symbol of good luck. Its shell is said to be filled with happiness.", 175, "Togepi's shell is filled with happiness and good fortune. It can absorb positive emotions from others, which causes its shell to become more vibrant in color."));
            pokemons.Add(new Pokemon("Togetic", 0.6, 3.2, "Happiness", "Hustle", "Fairy & Flying", 1, "Togekiss", "It is said to be a messenger of happiness. It disperses its own kindness and joy to those around it.", 176, "Togetic is a very kind Pokémon. It appears to people who are pure of heart and showers them with happiness by sprinkling its sparkling dust."));
            pokemons.Add(new Pokemon("Natu", 0.2, 2.0, "Tiny Bird", "Synchronize", "Psychic & Flying", 1, "Xatu", "It is extremely good at jumping. It gathers on tree branches and jumps from branch to branch.", 177, "Natu is a curious Pokémon that is always hopping around. It has underdeveloped wings, so it cannot fly, but it can jump incredibly high to reach branches."));
            pokemons.Add(new Pokemon("Xatu", 1.5, 15.0, "Mystic", "Synchronize", "Psychic & Flying", 1, "None", "This odd Pokémon can see both the past and the future. It stares at the sun all day long.", 178, "Xatu is always meditating, standing still and staring at the sun. By doing so, it gains the ability to see into the past and the future, though it never acts on what it sees."));
            pokemons.Add(new Pokemon("Mareep", 0.6, 7.8, "Wool", "Static", "Electric", 1, "Flaaffy", "Its fluffy wool stores static electricity. The more charge it builds up, the more luminous its body becomes.", 179, "Mareep's fluffy coat stores static electricity. If it is rubbed, its wool grows, and it produces more electricity. Its body glows when it is fully charged."));
            pokemons.Add(new Pokemon("Flaaffy", 0.8, 13.3, "Wool", "Static", "Electric", 1, "Ampharos", "As a result of storing too much electricity, it developed patches where even downy wool won't grow.", 180, "Flaaffy has wool that is excellent for conducting electricity. Its rubbery skin prevents it from being shocked by its own electricity, which it stores in its wool."));
            pokemons.Add(new Pokemon("Ampharos", 1.4, 61.5, "Light", "Static", "Electric", 1, "None", "The tip of its tail shines brightly. In olden times, it was used as a beacon for ships at sea.", 181, "Ampharos's tail is so bright that it can be seen from far away. It uses its light to signal to others and has historically been used as a lighthouse."));
            pokemons.Add(new Pokemon("Bellossom", 0.4, 5.8, "Flower", "Chlorophyll", "Grass", 1, "None", "When the heavy rains end, it is drawn out into the open to dance in the warm sunlight. Its dancing is famous.", 182, "Bellossom are known for their beautiful dancing. They gather in the sunlight and dance together. The more they dance, the more vibrant their colors become."));
            pokemons.Add(new Pokemon("Marill", 0.4, 8.5, "Aqua Mouse", "Thick Fat", "Water & Fairy", 1, "Azumarill", "Its body is covered with water-repellent fur. Because of this, it can stay dry even when playing in water.", 183, "Marill's fur is so water-repellent that it can swim without getting wet. Its tail is filled with oil that allows it to float on water without sinking."));
            pokemons.Add(new Pokemon("Azumarill", 0.8, 28.5, "Aqua Rabbit", "Thick Fat", "Water & Fairy", 1, "None", "It has long, floppy ears that act like rudders. They enable it to make sharp turns in the water.", 184, "Azumarill's ears are essential for its agile swimming. It fills its large body with air to float, and its powerful legs allow it to propel itself through water."));
            pokemons.Add(new Pokemon("Sudowoodo", 1.2, 38.0, "Imitation", "Sturdy", "Rock", 1, "None", "It disguises itself as a tree to avoid attack. It hates water, so it will disappear if it starts raining.", 185, "Sudowoodo mimics a tree to fool its enemies. It is actually a rock-type Pokémon and hates water, so it will run away when it rains to protect its body."));
            pokemons.Add(new Pokemon("Politoed", 1.1, 33.9, "Frog", "Water Absorb", "Water", 1, "None", "When it expands its throat to croak out its call, nearby Poliwag and Poliwhirl gather immediately.", 186, "Politoed is the leader of Poliwag and Poliwhirl. Its croak is so powerful that it can summon its kin from miles around. The longer its curled hair is, the more respect it commands."));
            pokemons.Add(new Pokemon("Hoppip", 0.4, 0.5, "Cottonweed", "Chlorophyll", "Grass & Flying", 1, "Skiploom", "It drifts on winds. It is said that when Hoppip gather in fields and mountains, spring is on its way.", 187, "Hoppip is a light and airy Pokémon that is carried by the wind. If its body becomes too wet, it cannot float and becomes vulnerable."));
            pokemons.Add(new Pokemon("Skiploom", 0.6, 1.0, "Cottonweed", "Chlorophyll", "Grass & Flying", 1, "Jumpluff", "It blooms when the weather warms. It floats in the sky to enjoy the warmth of the sunlight.", 188, "Skiploom's flower blooms when the temperature rises. When it is cold, the flower closes up again. It floats on the wind to find a warm place to bask."));
            pokemons.Add(new Pokemon("Jumpluff", 0.8, 3.0, "Cottonweed", "Chlorophyll", "Grass & Flying", 1, "None", "It drifts through the air on its fluffy cotton spores. When it gets cold, it gathers with others to hibernate.", 189, "Jumpluff uses its cotton-like spores to catch the wind and travel great distances. It scatters its spores during its journey to spread its genes."));
            pokemons.Add(new Pokemon("Aipom", 0.8, 11.5, "Long Tail", "Run Away", "Normal", 1, "Ambipom", "Its tail is so powerful that it can lift a grown human. It uses its tail to grip tree branches and hang.", 190, "Aipom's tail is its most important limb. It uses it for everything, from swinging through trees to picking up food. The hand on its tail is very dexterous."));
            pokemons.Add(new Pokemon("Sunkern", 0.3, 1.8, "Seed", "Chlorophyll", "Grass", 1, "Sunflora", "It is very weak. It may fall over if it is hit by a strong gust of wind. It only moves when the sun is out.", 191, "Sunkern is one of the weakest Pokémon in existence. It survives by absorbing nutrients from the soil and hiding under leaves. It can only move during the day."));
            pokemons.Add(new Pokemon("Sunflora", 0.8, 8.5, "Sun", "Chlorophyll", "Grass", 1, "None", "It converts solar energy into nutrients. It moves around actively in the daytime when it is warm.", 192, "Sunflora is a very energetic Pokémon during the day. It follows the sun across the sky, absorbing its rays. At night, it closes its petals and rests."));
            pokemons.Add(new Pokemon("Yanma", 1.2, 38.0, "Clear Wing", "Speed Boost", "Bug & Flying", 1, "Yanmega", "Its eyes can see 360 degrees. It can flap its wings at high speed to hover or stop suddenly.", 192, "Yanma is an incredibly agile flyer. Its large eyes allow it to see in all directions, and its wings can beat so fast that it can hover in place."));
            pokemons.Add(new Pokemon("Wooper", 0.4, 8.5, "Water Fish", "Damp", "Water & Ground", 1, "Quagsire", "It lives in cold water. When it gets cold outside, it uses its felt-like fur to keep warm.", 194, "Wooper lives in water but also has a membrane that allows it to breathe air on land. Its body is covered in a slippery film that makes it hard to grasp."));
            pokemons.Add(new Pokemon("Quagsire", 1.4, 75.0, "Water Fish", "Damp", "Water & Ground", 1, "None", "It has a laid‑back nature. It is very slow and oblivious, but it doesn't care if its head is bumped.", 195, "Quagsire is a very relaxed Pokémon. It is often seen bumping its head on boat hulls or riverbeds. It is so carefree that it doesn't even notice the pain."));
            pokemons.Add(new Pokemon("Espeon", 0.9, 26.5, "Sun", "Synchronize", "Psychic", 1, "None", "It uses the fine fur on its body to sense air currents and predict the weather or its foe's movements.", 196, "Espeon is extremely loyal to its trainer. It can predict the weather and its opponent's next moves by reading air currents with the sensitive fur on its body."));
            pokemons.Add(new Pokemon("Umbreon", 1.0, 27.0, "Moonlight", "Synchronize", "Dark", 1, "None", "When it gets dark, the rings on its body begin to glow. These rings strike fear into the hearts of anyone nearby.", 197, "Umbreon hides in the dark and waits for prey. The rings on its body glow when it is excited or when it is about to attack. It is a very mysterious Pokémon."));
            pokemons.Add(new Pokemon("Murkrow", 0.5, 2.1, "Darkness", "Insomnia", "Dark & Flying", 1, "Honchkrow", "It is believed that seeing this Pokémon at night will bring about ominous occurrences.", 198, "Murkrow loves shiny objects. It is known to sneak into people's homes to steal jewelry and other valuables. It is considered a bad omen in many cultures."));
            pokemons.Add(new Pokemon("Slowking", 2.0, 79.5, "Royal", "Oblivious", "Water & Psychic", 1, "None", "It has incredible intellect and intuition. Its Shellder-induced brain venom gives it a huge IQ.", 199, "When a Shellder bites Slowpoke's head, the venom it injects causes an explosion of intelligence. Slowking becomes incredibly wise but also very lazy."));
            pokemons.Add(new Pokemon("Misdreavus", 0.7, 1.0, "Screech", "Levitate", "Ghost", 1, "Mismagius", "It loves to bite and yank people's hair from behind without warning, just to see their shocked reactions.", 200, "Misdreavus is a prankster that loves to scare people. It hides in dark places and makes a screeching sound to frighten its victims."));
            pokemons.Add(new Pokemon("Unown", 0.5, 5.0, "Symbol", "Levitate", "Psychic", 1, "None", "Their shapes look like hieroglyphs on ancient walls. It is said that the two are somehow related.", 201, "Unown are mysterious Pokémon that resemble ancient writing. They are usually found in groups and are said to communicate telepathically with each other."));
            pokemons.Add(new Pokemon("Wobbuffet", 1.3, 28.5, "Patient", "Shadow Tag", "Psychic", 1, "None", "It hates light and shock. If attacked, it inflates its body to build up its counterattack.", 202, "Wobbuffet never attacks first. It waits patiently for its opponent to strike, then doubles the force of the attack and sends it back with double the power."));
            pokemons.Add(new Pokemon("Girafarig", 1.5, 41.5, "Long Neck", "Inner Focus", "Normal & Psychic", 1, "None", "Its tail has a small brain of its own. It is gentle, but if you approach its tail incorrectly, it will bite.", 202, "Girafarig has two heads—one in front and one in its tail. The head on its tail thinks independently and will attack if it feels threatened. It eats grass and uses its tail to watch for danger."));
            pokemons.Add(new Pokemon("Pineco", 0.6, 7.2, "Bagworm", "Sturdy", "Bug", 1, "Forretress", "It looks like a pinecone. It hangs from a tree branch and waits for prey to come to it.", 204, "Pineco hangs from tree branches, disguised as a pinecone. When prey approaches, it will suddenly open its shell and attack. It is a very patient hunter."));
            pokemons.Add(new Pokemon("Forretress", 1.2, 125.8, "Bagworm", "Sturdy", "Bug & Steel", 1, "None", "It is encased in a steel-hard shell. It launches spikes from its body in all directions to repel attackers.", 205, "Forretress's shell is as hard as steel. It remains attached to a tree, barely moving, but if disturbed, it will explode with a volley of spikes."));
            pokemons.Add(new Pokemon("Dunsparce", 1.5, 14.0, "Land Snake", "Serene Grace", "Normal", 1, "None", "It hides deep inside caves where no light ever reaches it. It remains motionless for extremely long periods.", 206, "Dunsparce is a rarely seen Pokémon. It uses its tail to dig through the ground. When threatened, it can fly a little using its tiny wings."));
            pokemons.Add(new Pokemon("Gligar", 1.1, 64.8, "Fly Scorpion", "Hyper Cutter", "Ground & Flying", 1, "Gliscor", "It glides without making a sound. It wraps its prey in its tail and waits for it to stop moving.", 207, "Gligar uses its claws and tail to climb walls. It glides through the air silently to approach its prey. Its face is very friendly, but it is a fierce predator."));
            pokemons.Add(new Pokemon("Steelix", 9.2, 400.0, "Iron Snake", "Rock Head", "Steel & Ground", 1, "None", "It is said that if an Onix lives for over 100 years, its body composition changes to become diamond-like.", 208, "Steelix's body is harder than any other metal. It lives deep underground and can tunnel through the earth at incredible speeds, causing massive tremors."));
            pokemons.Add(new Pokemon("Snubbull", 0.6, 7.8, "Fairy", "Intimidate", "Fairy", 1, "Granbull", "It is a timid Pokémon, despite its frightening face. It is popular with women because of its appearance.", 209, "Snubbull looks scary, but it is actually a very timid Pokémon. It often frightens itself with its own reflection. It is very popular among women for its cute face."));
            pokemons.Add(new Pokemon("Granbull", 1.4, 48.7, "Fairy", "Intimidate", "Fairy", 1, "None", "It is actually a coward, but it will start a fight if its territory is threatened. Its bite is very powerful.", 210, "Granbull has powerful jaws that can crush a car. Despite its fearsome appearance, it is a gentle giant that is very protective of its trainer."));
            pokemons.Add(new Pokemon("Qwilfish", 0.5, 3.9, "Balloon", "Poison Point", "Water & Poison", 1, "None", "It shoots water to escape. Its fins and spine are filled with a potent poison that can paralyze predators.", 211, "Qwilfish inflates its body when threatened, making its poisonous spines stand on end. The poison is strong enough to cause paralysis."));
            pokemons.Add(new Pokemon("Scizor", 1.8, 118.0, "Pincer", "Swarm", "Bug & Steel", 1, "None", "It has a steel-hard body. It uses its wings to adjust its body temperature and to intimidate opponents.", 212, "Scizor's body is as hard as steel. Its pincers are incredibly strong, but because they are so heavy, it has trouble using them for long periods."));
            pokemons.Add(new Pokemon("Shuckle", 0.6, 20.5, "Mold", "Sturdy", "Bug & Rock", 1, "None", "It stores berries in its shell. The berries eventually ferment to become a delicious, potent juice.", 213, "Shuckle is a very slow and weak Pokémon, but its shell is incredibly tough. It hides under rocks and stores berries in its shell to make juice."));
            pokemons.Add(new Pokemon("Heracross", 1.5, 54.0, "Single Horn", "Swarm", "Bug & Fighting", 1, "None", "It is very powerful and loves to show off its strength. It is known to throw its enemies using its horn.", 214, "Heracross is a gentle Pokémon that loves to suck the sap from trees. It is incredibly strong and can easily lift objects ten times its own weight."));
            pokemons.Add(new Pokemon("Sneasel", 0.9, 28.0, "Sharp Claw", "Inner Focus", "Dark & Ice", 1, "Weavile", "It is very cunning and quick. It sneaks up on prey from behind and slashes it with its sharp claws.", 215, "Sneasel is a nocturnal Pokémon that lives in mountains. It uses its claws to climb trees and steal eggs from bird Pokémon's nests."));
            pokemons.Add(new Pokemon("Teddiursa", 0.6, 8.8, "Little Bear", "Pickup", "Normal", 1, "Ursaring", "It always licks its paws because they are soaked in honey. It collects honey every day.", 216, "Teddiursa loves honey. It has a special ability to find honey from the scent alone. It always has honey on its paws and is constantly licking them."));
            pokemons.Add(new Pokemon("Ursaring", 1.8, 125.8, "Hibernator", "Guts", "Normal", 1, "None", "In the forests inhabited by Ursaring, it is said that you should not pick berries from trees.", 217, "Ursaring is a very territorial Pokémon. It marks its territory by scratching trees with its powerful claws. During the winter, it hibernates in a cave."));
            pokemons.Add(new Pokemon("Slugma", 0.7, 35.0, "Lava", "Magma Armor", "Fire", 1, "Magcargo", "It is a species of Pokémon that never stops moving. If it stops, its magma body cools and hardens.", 218, "Slugma's body is made of molten magma. It is constantly moving to keep its body from cooling and hardening. It leaves a trail of fire wherever it goes."));
            pokemons.Add(new Pokemon("Magcargo", 0.8, 55.0, "Lava", "Magma Armor", "Fire & Rock", 1, "None", "Its body is as hot as lava and is always billowing heat. It will cool and harden if it rains.", 219, "Magcargo's shell is actually made of cooled magma. Its body temperature is over 10,000 degrees Fahrenheit, which is hot enough to melt anything."));
            pokemons.Add(new Pokemon("Swinub", 0.4, 6.5, "Pig", "Oblivious", "Ice & Ground", 1, "Piloswine", "It rubs its snout on the ground to find food. It sometimes digs up hot springs.", 220, "Swinub has a very sensitive nose. It can sniff out mushrooms and berries buried under the snow and ice. Its favorite food is found in hot springs."));
            pokemons.Add(new Pokemon("Piloswine", 1.1, 55.8, "Swine", "Oblivious", "Ice & Ground", 1, "Mamoswine", "Its shaggy fur is so strong that it can protect it from attacks. Its tusks are made of ice.", 221, "Piloswine is covered in long, thick fur that protects it from the cold. It uses its tusks to dig through the ice in search of food."));
            pokemons.Add(new Pokemon("Corsola", 0.6, 5.0, "Coral", "Hustle", "Water & Rock", 1, "None", "It lives in warm southern seas. If its habitat becomes polluted, its pretty coral branches lose color.", 222, "Corsola's branches are made of a hard, coral-like substance. They are very popular as souvenirs. It is very sensitive to pollution, which can cause it to die."));
            pokemons.Add(new Pokemon("Remoraid", 0.6, 12.0, "Jet", "Hustle", "Water", 1, "Octillery", "It uses its tail fin to precision-snipe flying bugs. It can shoot water with amazing accuracy.", 223, "Remoraid can shoot down flying bugs with a stream of water from its mouth. It is an excellent shot. It often attaches itself to Mantine to travel."));
            pokemons.Add(new Pokemon("Octillery", 0.9, 28.5, "Jet", "Suction Cups", "Water", 1, "None", "It instinctively sneaks into rocky holes. If it gets sleepy, it steals the nesting place of others.", 224, "Octillery has a hard, powerful beak hidden under its tentacles. It uses its tentacles to trap prey and its beak to crush them. It is very territorial."));
            pokemons.Add(new Pokemon("Delibird", 0.9, 16.0, "Delivery", "Vital Spirit", "Ice & Flying", 1, "None", "It carries food all day long. There are stories about lost people being saved by the food it had.", 225, "Delibird stores food in its tail pouch and delivers it to people and Pokémon in need. It is a very generous Pokémon that is always willing to share."));
            pokemons.Add(new Pokemon("Mantine", 2.1, 220.0, "Kite", "Swift Swim", "Water & Flying", 1, "None", "It swims elegantly and gracefully. Remoraid often swim alongside it, hitching a ride for food scraps.", 226, "Mantine is a gentle giant of the sea. It loves to swim in the open ocean and will often let Remoraid attach themselves to its fins for protection."));
            pokemons.Add(new Pokemon("Skarmory", 1.7, 50.5, "Armor Bird", "Keen Eye", "Steel & Flying", 1, "None", "Its body is covered with a sturdy armor of razor-sharp blades. It flies at speeds of up to 180 mph.", 227, "Skarmory's feathers are made of sharp, metallic blades. It lives in rugged mountains and is rarely seen. Its young are raised in nests made of collected bones."));
            pokemons.Add(new Pokemon("Houndour", 0.6, 10.8, "Dark", "Early Bird", "Dark & Fire", 1, "Houndoom", "It uses different types of cries to communicate with its pack and to corner prey in the dark.", 228, "Houndour hunts in packs, communicating with various cries. They are very coordinated and can surround and take down prey much larger than themselves."));
            pokemons.Add(new Pokemon("Houndoom", 1.4, 35.0, "Dark", "Early Bird", "Dark & Fire", 1, "None", "The flames it breathes are so hot that they can cause wounds that will never heal.", 229, "Houndoom's flames are extremely painful. The pain from its fire never goes away. It is a very feared and respected Pokémon in the wild."));
            pokemons.Add(new Pokemon("Kingdra", 1.8, 152.0, "Dragon", "Swift Swim", "Water & Dragon", 1, "None", "It lives in caves on the seafloor. It creates whirlpools and can even drag down large ships.", 230, "Kingdra lives in the deepest parts of the ocean. It can create whirlpools by yawning. Its power is immense, and it is known to be a very rare and powerful Pokémon."));
            pokemons.Add(new Pokemon("Phanpy", 0.5, 33.5, "Long Nose", "Pickup", "Ground", 1, "Donphan", "It is very strong despite its size. It uses its trunk to pick up and carry things.", 231, "Phanpy is a playful Pokémon that loves to spray water from its nose. It is very strong for its size and can easily carry a grown adult on its back."));
            pokemons.Add(new Pokemon("Donphan", 1.1, 120.0, "Armor", "Sturdy", "Ground", 1, "None", "It has a hard, armor-like hide. It attacks by curling into a ball and rolling into its enemies.", 232, "Donphan's skin is so tough that it can repel even cannon fire. It curls into a ball and rolls at high speed to attack its opponents, leaving a trail of destruction."));
            pokemons.Add(new Pokemon("Porygon2", 0.6, 32.5, "Virtual", "Trace", "Normal", 1, "Porygon-Z", "It was upgraded to be able to travel through alien dimensions. It moves freely in cyberspace.", 233, "Porygon2 is an artificial Pokémon created by upgrading Porygon with planetary development data. It is capable of traveling through digital space."));
            pokemons.Add(new Pokemon("Stantler", 1.4, 71.2, "Big Horn", "Intimidate", "Normal", 1, "None", "Its curved antlers are prized as works of art. They are so powerful that they can bend thick trees.", 234, "Stantler's antlers change shape with the seasons. The orbs on its antlers create a strange distortion in the air, making people and Pokémon lost."));
            pokemons.Add(new Pokemon("Smeargle", 1.2, 58.0, "Painter", "Own Tempo", "Normal", 1, "None", "It marks its territory with its tail. It uses a fluid that comes out of the tip of its tail to paint.", 235, "Smeargle is an artist Pokémon. It uses the fluid at the tip of its tail to paint. It marks its territory with its art, and its paintings are highly prized."));
            pokemons.Add(new Pokemon("Tyrogue", 0.7, 21.0, "Scuffle", "Guts", "Fighting", 1, "Hitmonlee/Hitmonchan/Hitmontop", "It is always full of energy and loves to fight. It grows stronger by challenging others to battles.", 236, "Tyrogue is a small but energetic Pokémon. It loves to fight and will challenge anyone, regardless of size. Its eagerness to battle is unmatched."));
            pokemons.Add(new Pokemon("Hitmontop", 1.4, 48.0, "Handstand", "Intimidate", "Fighting", 1, "None", "It fights while spinning like a top. It can deliver a powerful kick while spinning at high speed.", 237, "Hitmontop fights by spinning on its head. It uses its legs like whips to strike its opponents. It is known for its unique and mesmerizing fighting style."));
            pokemons.Add(new Pokemon("Smoochum", 0.4, 6.0, "Kiss", "Oblivious", "Ice & Psychic", 1, "Jynx", "It is always looking for a kiss. It tests things by licking them to see if they taste good.", 238, "Smoochum has very sensitive lips. It uses them to examine objects and people. It is very curious and loves to give kisses to those it likes."));
            pokemons.Add(new Pokemon("Elekid", 0.6, 23.5, "Electric", "Static", "Electric", 1, "Electabuzz", "It rotates its arms to generate electricity. It stores the electricity in its body and then discharges it.", 239, "Elekid is a very energetic Pokémon. It loves to play during thunderstorms. It can generate electricity by spinning its arms."));
            pokemons.Add(new Pokemon("Magby", 0.7, 21.4, "Live Coal", "Flame Body", "Fire", 1, "Magmar", "It is found in volcanic areas. Its body temperature is about 600 degrees Fahrenheit.", 240, "Magby lives near volcanoes. Its body is incredibly hot, and it breathes flames. It is very playful and loves to play with fire."));
            pokemons.Add(new Pokemon("Miltank", 1.2, 75.5, "Milk Cow", "Thick Fat", "Normal", 1, "None", "Its milk is highly nutritious and is used to raise healthy babies. It is known to be a gentle and caring Pokémon.", 241, "Miltank produces delicious and highly nutritious milk. It is a very gentle Pokémon that loves to take care of its trainer. Its milk is a popular treat."));
            pokemons.Add(new Pokemon("Blissey", 1.5, 46.8, "Happiness", "Natural Cure", "Normal", 1, "None", "It has a very kind heart. It will share its nutritious eggs with anyone who is sad or injured.", 242, "Blissey is a very caring Pokémon. It carries a special egg that is filled with happiness. It will give its egg to anyone in need, spreading joy and health."));
            pokemons.Add(new Pokemon("Raikou", 1.9, 178.0, "Thunder", "Pressure", "Electric", 1, "None", "It is said to have descended from the sky on a lightning bolt. It can travel at speeds exceeding 600 mph.", 243, "Raikou is a legendary Pokémon that represents the speed of lightning. It is always accompanied by thunder. It is one of the legendary beasts of Johto."));
            pokemons.Add(new Pokemon("Entei", 2.1, 198.0, "Volcano", "Pressure", "Fire", 1, "None", "It is said that when it roars, a volcano erupts. It creates massive eruptions wherever it goes.", 244, "Entei is a legendary Pokémon that represents the heat of a volcano. It is said to be born from the eruption of a volcano. It is one of the legendary beasts of Johto."));
            pokemons.Add(new Pokemon("Suicune", 2.0, 187.0, "Aurora", "Pressure", "Water", 1, "None", "It is said to be the embodiment of the north wind. It can instantly purify any water it touches.", 245, "Suicune is a legendary Pokémon that represents the purity of water. It travels across the world to purify polluted water. It is one of the legendary beasts of Johto."));
            pokemons.Add(new Pokemon("Larvitar", 0.6, 72.0, "Rock Skin", "Guts", "Rock & Ground", 1, "Pupitar", "It is born deep underground. It eats soil and eventually becomes a beautiful butterfly-like creature.", 246, "Larvitar is a rare Pokémon that lives deep in mountains. It eats soil and rocks to grow. It is very strong for its size and is often found in caves."));
            pokemons.Add(new Pokemon("Pupitar", 1.2, 152.0, "Hard Shell", "Shed Skin", "Rock & Ground", 1, "Tyranitar", "It is encased in a gas-like shell. It moves around by expelling pressurized gas from its body.", 247, "Pupitar's shell is as hard as rock. It cannot move much, but it can propel itself by releasing gas from its body. It is waiting to evolve into Tyranitar."));
            pokemons.Add(new Pokemon("Tyranitar", 2.0, 202.0, "Armor", "Sand Stream", "Rock & Dark", 1, "None", "Its body is made of rock-hard armor. It can cause massive earthquakes by just walking.", 248, "Tyranitar is a very powerful and destructive Pokémon. It is so strong that it can change the landscape. It is feared for its immense power and is known as the God of Destruction."));
            pokemons.Add(new Pokemon("Lugia", 5.2, 216.0, "Diving", "Pressure", "Psychic & Flying", 1, "None", "It is said to be the guardian of the seas. It can cause a 40-day storm by flapping its wings.", 249, "Lugia is a legendary Pokémon that lives deep in the ocean. It has immense power and can calm or cause storms. It is rarely seen by humans."));
            pokemons.Add(new Pokemon("Ho-Oh", 3.8, 199.0, "Rainbow", "Pressure", "Fire & Flying", 1, "None", "It has a beautiful, rainbow-colored plumage. It is said to bring happiness to those who see it.", 250, "Ho-Oh is a legendary Pokémon that lives at the top of a rainbow. It is said to have the power to resurrect the dead. Its appearance brings eternal happiness."));
            pokemons.Add(new Pokemon("Celebi", 0.6, 5.0, "Time Travel", "Natural Cure", "Psychic & Grass", 1, "None", "It has the power to travel through time. It is known as the voice of the forest and appears only in peaceful times.", 251, "Celebi is a mythical Pokémon that can travel through time. It is very shy and only appears in times of peace. It brings life and prosperity to the forests it visits."));
            pokemons.Add(new Pokemon("Treecko", 0.5, 5.0, "Wood Gecko", "Overgrow", "Grass", 1, "Grovyle", "It makes its nest in a giant tree in the forest. It scalates trees with the small hooks on its feet.", 252, "Treecko has small hooks on the bottom of its feet that enable it to scale vertical walls. It attacks by slamming foes with its thick tail."));
            pokemons.Add(new Pokemon("Grovyle", 0.9, 21.6, "Wood Gecko", "Overgrow", "Grass", 1, "Sceptile", "It lives in dense jungles. It leaps from branches to branches with incredible speed and agility.", 253, "The leaves growing out of its body are convenient for camouflaging it from enemies in the forest. This Pokémon is a master at climbing trees in jungles."));
            pokemons.Add(new Pokemon("Sceptile", 1.7, 52.2, "Forest", "Overgrow", "Grass", 1, "None", "The leaves on its body are very sharp and can be used as swords. It is very agile and leaps all over the branches of trees.", 254, "The leaves growing on Sceptile's body are very sharp edged. This Pokémon is very agile - it leaps all over the branches of trees and jumps on its foe from above or behind."));
            pokemons.Add(new Pokemon("Torchic", 0.4, 2.5, "Chick", "Blaze", "Fire", 1, "Combusken", "A fire burns inside, so it feels very warm to hug. It launches fireballs of over 1,800 degrees F.", 255, "Torchic sticks with its Trainer, following behind with unsteady steps. This Pokémon breathes fire of over 1,800 degrees F, including fireballs that leave the foe scorched black."));
            pokemons.Add(new Pokemon("Combusken", 0.9, 19.5, "Young Fowl", "Blaze", "Fire & Fighting", 1, "Blaziken", "It launches kicks while spinning. It can knock down its opponent with one kick.", 256, "Combusken toughens up its legs and thighs by running through fields and mountains. This Pokémon's legs possess both speed and power, enabling it to dole out ten kicks in one second."));
            pokemons.Add(new Pokemon("Blaziken", 1.9, 52.0, "Blaze", "Blaze", "Fire & Fighting", 1, "None", "Its punch can throw a truck. It can also unleash fire from its wrists, burning the foe.", 257, "Blaziken has incredibly strong legs that allow it to easily clear a 30-story building. Its fiery kicks can leave opponents with severe burns."));
            pokemons.Add(new Pokemon("Mudkip", 0.4, 7.6, "Mud Fish", "Torrent", "Water", 1, "Marshtomp", "Its large tail fin propels it through water with powerful acceleration. It is strong enough to lift boulders.", 258, "The fin on Mudkip's head acts as highly sensitive radar. Using this fin to sense movements of water and air, this Pokémon can determine what is taking place around it without using its eyes."));
            pokemons.Add(new Pokemon("Marshtomp", 0.7, 28.0, "Mud Fish", "Torrent", "Water & Ground", 1, "Swampert", "Its sturdy legs give it a sure footing, even in mud. It burrows in mud and sleeps, ignoring the tide.", 259, "The surface of Marshtomp's body is enveloped by a thin, sticky film that enables it to live on land. This Pokémon plays in mud on beaches when the ocean tide is low."));
            pokemons.Add(new Pokemon("Swampert", 1.5, 81.9, "Mud Fish", "Torrent", "Water & Ground", 1, "None", "It can swim while towing a large ship. It bashes down foes with a swing of its thick arms.", 260, "Swampert is very strong. It has enough power to easily drag a boulder weighing more than a ton. This Pokémon also has powerful vision that lets it see even in murky water."));
            pokemons.Add(new Pokemon("Poochyena", 0.5, 13.6, "Bite", "Run Away", "Dark", 1, "Mightyena", "A Pokémon with a persistent nature, it will chase its chosen prey until the prey becomes exhausted.", 261, "Poochyena is an omnivorous Pokémon that will eat anything. It is known for its tenacity and will chase prey until it collapses from exhaustion."));
            pokemons.Add(new Pokemon("Mightyena", 1.0, 37.0, "Bite", "Intimidate", "Dark", 1, "None", "It hunks prey in a pack. It never disobeys the commands of a skilled Trainer.", 262, "Mightyena is a very loyal Pokémon. It obeys its Trainer's commands perfectly and is known to be a very effective hunter when working in a pack."));
            pokemons.Add(new Pokemon("Zigzagoon", 0.4, 17.5, "Tiny Raccoon", "Pickup", "Normal", 1, "Linoone", "It walks in zigzag fashion. It is good at finding items and can be found in fields and forests.", 263, "Zigzagoon is a curious Pokémon that is always interested in everything it sees. It wanders in a zigzag pattern, looking for interesting items and food."));
            pokemons.Add(new Pokemon("Linoone", 0.5, 32.5, "Rushing", "Pickup", "Normal", 1, "None", "It runs at over 60 mph. It races through fields and mountains, always checking its surroundings.", 264, "Linoone is a very fast runner. It can reach speeds of up to 60 mph. It uses its speed to chase down prey and to escape from danger."));
            pokemons.Add(new Pokemon("Wurmple", 0.3, 3.6, "Worm", "Shield Dust", "Bug", 1, "Silcoon/Cascoon", "It lives among the leaves. It sprays a powerful poison from its tail to repel enemies.", 265, "Wurmple is a common Pokémon found in forests. It eats leaves and sheds its skin many times before it is ready to evolve."));
            pokemons.Add(new Pokemon("Silcoon", 0.6, 10.0, "Cocoon", "Shed Skin", "Bug", 1, "Beautifly", "It wraps silk around its body and waits for evolution. It can endure any attack.", 266, "Silcoon attaches itself to a tree branch and wraps itself in silk. It hardly moves while it awaits evolution, but its body is preparing for the change inside."));
            pokemons.Add(new Pokemon("Beautifly", 1.0, 28.4, "Butterfly", "Swarm", "Bug & Flying", 1, "None", "Its wings are beautiful and colorful. It flies around to collect nectar and pollen.", 267, "Beautifly has a long mouthpart that it uses to suck nectar from flowers. It is a very colorful and beautiful Pokémon, but it can be aggressive if its territory is threatened."));
            pokemons.Add(new Pokemon("Cascoon", 0.7, 11.5, "Cocoon", "Shed Skin", "Bug", 1, "Dustox", "It never forgets any attack it endured while in its cocoon. It is preparing to evolve.", 268, "Cascoon is a patient Pokémon. It hangs from a tree branch and waits for evolution. It never forgets any attack it endures during this period."));
            pokemons.Add(new Pokemon("Dustox", 1.2, 31.6, "Poison Moth", "Shield Dust", "Bug & Poison", 1, "None", "It is attracted to light. It is nocturnal and is drawn to the lights of cities.", 269, "Dustox is a nocturnal Pokémon. It is strongly attracted to light and can be seen gathering around streetlights at night. Its wings are covered in a poisonous powder."));
            pokemons.Add(new Pokemon("Lotad", 0.5, 2.6, "Water Weed", "Swift Swim", "Water & Grass", 1, "Lombre", "It searches about for clean water. If it does not drink water for too long, its leaf wilts.", 270, "Lotad lives in ponds and lakes. It has a lily pad on its head that allows it to float on water. If the lily pad dries out, it becomes weak."));
            pokemons.Add(new Pokemon("Lombre", 1.2, 32.5, "Jolly", "Swift Swim", "Water & Grass", 1, "Ludicolo", "It is nocturnal and becomes active at night. It lives at the water's edge and is often overlooked.", 271, "Lombre is a mischievous Pokémon that loves to play pranks on people. It lives at the edge of water and is often mistaken for a weed."));
            pokemons.Add(new Pokemon("Ludicolo", 1.5, 55.0, "Carefree", "Swift Swim", "Water & Grass", 1, "None", "If it hears a festive tune, it begins moving in rhythm. It is known to brighten moods.", 272, "Ludicolo is a very cheerful Pokémon. It loves to dance and will start moving if it hears music. The more it dances, the more energetic it becomes."));
            pokemons.Add(new Pokemon("Seedot", 0.5, 4.0, "Acorn", "Chlorophyll", "Grass", 1, "Nuzleaf", "It hangs from a tree branch using a string of silk. It drops down to attack when prey appears.", 273, "Seedot attaches itself to a tree branch using a silk-like thread. It looks exactly like an acorn, so it can fool its enemies. It drinks rainwater from its body."));
            pokemons.Add(new Pokemon("Nuzleaf", 1.0, 28.0, "Wily", "Chlorophyll", "Grass & Dark", 1, "Shiftry", "It lives in a forest that is so dense that no light can penetrate. It is skilled at sneaking up on enemies.", 274, "Nuzleaf lives deep in forests. It has a leaf on its head that it uses to sniff out prey. It is a very mischievous Pokémon that loves to startle people."));
            pokemons.Add(new Pokemon("Shiftry", 1.3, 59.6, "Wicked", "Chlorophyll", "Grass & Dark", 1, "None", "It lives in a forest that is so dense that no light can penetrate. It is said to be the embodiment of the wind.", 275, "Shiftry is a mysterious Pokémon that lives in dark forests. It can create powerful gusts of wind by fanning its large leaves. It is said to be able to blow away a house."));
            pokemons.Add(new Pokemon("Taillow", 0.3, 2.3, "Tiny Swallow", "Guts", "Normal & Flying", 1, "Swellow", "It is very brave and will challenge any opponent, no matter how strong. It will never give up.", 276, "Taillow is a very courageous Pokémon. It is small but will not back down from a fight, even against much larger opponents. It is very energetic and loves to fly."));
            pokemons.Add(new Pokemon("Swellow", 0.7, 19.8, "Swallow", "Guts", "Normal & Flying", 1, "None", "It flies high above the clouds. It dives at high speed to catch prey, clutching them with its claws.", 277, "Swellow is an incredibly fast flier. It soars high in the sky and dives at tremendous speeds to catch its prey. It never misses its target."));
            pokemons.Add(new Pokemon("Wingull", 0.6, 9.5, "Seagull", "Keen Eye", "Water & Flying", 1, "Pelipper", "It soars on ocean winds. It makes its nest on steep sea cliffs and takes fish from the sea.", 278, "Wingull is a seabird Pokémon. It uses its hollow bones to catch the wind and glide effortlessly over the ocean. It is often seen following ships."));
            pokemons.Add(new Pokemon("Pelipper", 1.2, 28.0, "Water Bird", "Keen Eye", "Water & Flying", 1, "None", "It is a very patient Pokémon. It skims the water's surface and scoops up prey with its large bill.", 279, "Pelipper has a large, stretchy beak that it uses to scoop up fish and water. It can carry small Pokémon in its beak and is known to be a helpful Pokémon."));
            pokemons.Add(new Pokemon("Ralts", 0.4, 6.6, "Feeling", "Synchronize", "Psychic & Fairy", 1, "Kirlia", "It senses the emotions of people and Pokémon. It hides when it senses hostility.", 280, "Ralts is a very shy Pokémon. It uses the horns on its head to sense the emotions of others. If it senses positive emotions, it will approach, but it will run from hostility."));
            pokemons.Add(new Pokemon("Kirlia", 0.8, 20.2, "Emotion", "Synchronize", "Psychic & Fairy", 1, "Gardevoir/Gallade", "It is highly perceptive of the emotions of others. It dances when it feels happy.", 281, "Kirlia is a very graceful Pokémon. It dances when it senses positive emotions from its Trainer. It can read the emotions of others with its horns."));
            pokemons.Add(new Pokemon("Gardevoir", 1.6, 48.4, "Embrace", "Synchronize", "Psychic & Fairy", 1, "None", "It has the power to create a small black hole. It will protect its Trainer at all costs.", 282, "Gardevoir is a very loyal Pokémon. It will do anything to protect its Trainer, even creating a small black hole if necessary. It is known for its elegant appearance."));
            pokemons.Add(new Pokemon("Surskit", 0.5, 1.7, "Pond Skater", "Swift Swim", "Bug & Water", 1, "Masquerain", "It lives in ponds. It secretes a sweet, sticky substance from its feet to walk on water.", 283, "Surskit can walk on water by secreting a sweet, oily fluid from its feet. It is often found on the surface of ponds, looking for prey."));
            pokemons.Add(new Pokemon("Masquerain", 0.8, 3.6, "Eyeball", "Intimidate", "Bug & Flying", 1, "None", "Its antennae have patterns that look like eyes. It uses them to intimidate its enemies.", 284, "Masquerain's large antennae have patterns that resemble eyes. It uses them to scare away predators. It is a very timid Pokémon and will flee if its intimidation fails."));
            pokemons.Add(new Pokemon("Shroomish", 0.4, 4.5, "Mushroom", "Effect Spore", "Grass", 1, "Breloom", "It loves to eat nutrients in the soil. It scatters spores to protect itself from danger.", 285, "Shroomish lives in damp forests. It uses its spores to defend itself and to attack. The spores can cause paralysis and poisoning."));
            pokemons.Add(new Pokemon("Breloom", 1.2, 39.2, "Mushroom", "Effect Spore", "Grass & Fighting", 1, "None", "Its short arms stretch when it throws punches. It can strike an opponent from a surprising distance.", 286, "Breloom's arms are short, but they can stretch when it attacks. It uses its powerful punches and its poisonous spores to defeat its opponents."));
            pokemons.Add(new Pokemon("Slakoth", 0.8, 24.0, "Slacker", "Truant", "Normal", 1, "Vigoroth", "It sleeps for 20 hours a day. It doesn't like to move and will only eat leaves that are within reach.", 287, "Slakoth is the laziest Pokémon in existence. It sleeps for most of the day and only moves when it needs to eat. It is very hard to motivate."));
            pokemons.Add(new Pokemon("Vigoroth", 1.4, 46.5, "Wild Monkey", "Vital Spirit", "Normal", 1, "Slaking", "Its heart beats at a rapid rate. It is always moving and can't sit still for even a minute.", 288, "Vigoroth is the complete opposite of its pre-evolution. It is constantly moving and has a heart that beats at a rapid rate. It is very aggressive."));
            pokemons.Add(new Pokemon("Slaking", 2.0, 130.5, "Lazy", "Truant", "Normal", 1, "None", "It is the world's most slothful Pokémon. It only moves to change position when it gets hungry.", 289, "Slaking is incredibly lazy. It only moves when it needs to eat, and it will lie down to save energy. However, when it does move, it is incredibly powerful."));
