            pokemons.Add(new Pokemon("Relicanth", 1.0, 23.4, "Longevity", "Swift Swim", "Water & Rock", 1, "None", "It is a rare Pokémon that has remained unchanged for 100 million years. It is a living fossil.", 369, "Relicanth is a living fossil that has not changed in 100 million years. It lives in deep, rocky waters and is very hard to find. It is a very ancient Pokémon."));
            pokemons.Add(new Pokemon("Luvdisc", 0.6, 8.7, "Rendezvous", "Swift Swim", "Water", 1, "None", "It lives in warm seas. It is said that couples who find a Luvdisc will have a happy relationship.", 370, "Luvdisc is a symbol of love. It is often given as a gift to loved ones. It lives in warm, tropical waters and is known for its heart-shaped body."));
            pokemons.Add(new Pokemon("Bagon", 0.6, 42.1, "Rock Head", "Rock Head", "Dragon", 1, "Shelgon", "It dreams of flying one day. It jumps off cliffs to practice flying, often hurting itself.", 371, "Bagon has a strong desire to fly. It will jump off cliffs to try to fly, but it always fails. It is a very determined Pokémon that never gives up."));
            pokemons.Add(new Pokemon("Shelgon", 1.1, 110.5, "Endurance", "Rock Head", "Dragon", 1, "Salamence", "It is encased in a hard shell. It eats and sleeps inside its shell while waiting for evolution.", 372, "Shelgon is enclosed in a hard, rock-like shell. It hardly moves while it waits for evolution. It eats and sleeps inside its shell, preparing for its final form."));
            pokemons.Add(new Pokemon("Salamence", 1.5, 102.6, "Dragon", "Intimidate", "Dragon & Flying", 1, "None", "It finally grew the wings it always dreamed of. It flies around expressing its joy.", 373, "Salamence finally achieved its dream of flying. It is very proud of its wings and loves to fly around showing them off. It is a very powerful and aggressive Pokémon."));
