            pokemons.Add(new Pokemon("Metang", 1.2, 202.5, "Iron Claw", "Clear Body", "Steel & Psychic", 1, "Metagross", "It is formed by two Beldum fusing together. It has a powerful brain that can control its opponents.", 375, "Metang is the result of two Beldum fusing. Its brain is much more powerful and can use psychic powers to control its opponents. It is very intelligent."));
            pokemons.Add(new Pokemon("Metagross", 1.6, 550.0, "Iron Leg", "Clear Body", "Steel & Psychic", 1, "None", "It is formed by two Metang fusing. It has four brains that work together to solve complex problems.", 376, "Metagross is the result of two Metang fusing. It has four brains that work as a supercomputer. It is incredibly intelligent and powerful."));
            pokemons.Add(new Pokemon("Regirock", 1.7, 230.0, "Rock Peak", "Clear Body", "Rock", 1, "None", "It is a legendary golem. Its body is made of rocks. If it gets damaged, it will add new rocks to repair itself.", 377, "Regirock is a legendary Pokémon made entirely of rock. It is very ancient and has lived for thousands of years. It can repair itself by adding new rocks to its body."));
