            pokemons.Add(new Pokemon("Latias", 1.4, 40.0, "Eon", "Levitate", "Dragon & Psychic", 1, "None", "It has a very gentle nature. It can become invisible and can communicate telepathically.", 380, "Latias is a very gentle and intelligent legendary Pokémon. It can become invisible and can understand human speech. It is very protective of its territory."));
            pokemons.Add(new Pokemon("Latios", 2.0, 60.0, "Eon", "Levitate", "Dragon & Psychic", 1, "None", "It has a very high level of intelligence. It can understand human speech and can telepathically communicate.", 381, "Latios is a highly intelligent legendary Pokémon. It can fly faster than a jet plane and can understand human speech. It is very loyal to its trainer."));
