            pokemons.Add(new Pokemon("Jirachi", 0.3, 1.1, "Wish", "Serene Grace", "Steel & Psychic", 1, "None", "It is said to grant wishes. It sleeps for 1,000 years and awakens for only 7 days.", 385, "Jirachi is a mythical Pokémon that can grant wishes. It sleeps for a thousand years and only awakens for a week. It is a very rare and powerful Pokémon."));
            pokemons.Add(new Pokemon("Deoxys", 1.7, 60.8, "DNA", "Pressure", "Psychic", 1, "None", "It is a DNA-based Pokémon that came from space. It can change forms to adapt to battle.", 386, "Deoxys is a mythical Pokémon that came from space. It is made of DNA and can change its form to adapt to any situation. It is a very powerful and intelligent Pokémon."));
            pokemons.Add(new Pokemon("Turtwig", 0.4, 10.2, "Tiny Leaf", "Overgrow", "Grass", 1, "Grotle", "Made from soil, the shell on its back hardens when it drinks water. It lives along lakes.", 387, "Turtwig's shell is made of earth. If it drinks water, the shell hardens and becomes more resistant. It is a very determined Pokémon that loves sunshine."));
