            pokemons.Add(new Pokemon("Monferno", 0.9, 22.0, "Playful", "Blaze", "Fire & Fighting", 1, "Infernape", "To intimidate attackers, it stretches the fire on its tail to make itself appear bigger.", 391, "Monferno is a very skilled fighter. It uses a combination of fire attacks and martial arts. It is very agile and can confuse its opponents with its speed."));
